"use client";

import * as React from "react";
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
  Badge,
  Button,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  Container,
  Label,
  RadioGroup,
  RadioGroupItem,
  Select,
  Separator,
  Slider,
  Switch,
  TimePicker,
} from "@gunjo/ui";

// ----------------------------------------------------------------------------
// Model
// ----------------------------------------------------------------------------

type ChannelId = "email" | "push" | "sms" | "inApp";

type NotificationTypeId =
  | "mentions"
  | "comments"
  | "follows"
  | "security"
  | "product";

type ChannelState = {
  master: boolean;
  types: Record<NotificationTypeId, boolean>;
};

type Settings = {
  channels: Record<ChannelId, ChannelState>;
  level: "all" | "mentions" | "none";
  digest: "instant" | "daily" | "weekly";
  quietHoursEnabled: boolean;
  quietStart: string; // "HH:mm"
  quietEnd: string; // "HH:mm"
  threshold: number; // 0-100 importance threshold
};

const CHANNELS: { id: ChannelId; label: string; description: string }[] = [
  {
    id: "email",
    label: "メール",
    description: "eemlis7.ke@gmail.com に送信",
  },
  {
    id: "push",
    label: "プッシュ",
    description: "ブラウザとモバイルのプッシュ通知",
  },
  { id: "sms", label: "SMS", description: "携帯電話へのショートメッセージ" },
  {
    id: "inApp",
    label: "アプリ内",
    description: "ベルアイコンとアクティビティフィード",
  },
];

const NOTIFICATION_TYPES: {
  id: NotificationTypeId;
  label: string;
  description: string;
}[] = [
  { id: "mentions", label: "メンション", description: "@メンションされたとき" },
  { id: "comments", label: "コメント", description: "自分のスレッドへの返信" },
  { id: "follows", label: "新しいフォロワー", description: "フォローされたとき" },
  { id: "security", label: "セキュリティ通知", description: "ログインやパスワードの変更" },
  { id: "product", label: "プロダクトの更新", description: "リリースやお知らせ" },
];

const DEFAULT_SETTINGS: Settings = {
  channels: {
    email: {
      master: true,
      types: { mentions: true, comments: true, follows: false, security: true, product: false },
    },
    push: {
      master: true,
      types: { mentions: true, comments: false, follows: false, security: true, product: false },
    },
    sms: {
      master: false,
      types: { mentions: false, comments: false, follows: false, security: true, product: false },
    },
    inApp: {
      master: true,
      types: { mentions: true, comments: true, follows: true, security: true, product: true },
    },
  },
  level: "all",
  digest: "daily",
  quietHoursEnabled: true,
  quietStart: "22:00",
  quietEnd: "07:00",
  threshold: 40,
};

// Stable structural clone for the in-memory "persisted" baseline.
function clone(s: Settings): Settings {
  return {
    ...s,
    channels: Object.fromEntries(
      Object.entries(s.channels).map(([k, v]) => [
        k,
        { master: v.master, types: { ...v.types } },
      ])
    ) as Settings["channels"],
  };
}

function settingsEqual(a: Settings, b: Settings): boolean {
  return JSON.stringify(a) === JSON.stringify(b);
}

// ----------------------------------------------------------------------------
// Page
// ----------------------------------------------------------------------------

export default function NotificationSettingsPage() {
  // `saved` is the in-memory persisted baseline; `draft` is the working copy.
  const [saved, setSaved] = React.useState<Settings>(() => clone(DEFAULT_SETTINGS));
  const [draft, setDraft] = React.useState<Settings>(() => clone(DEFAULT_SETTINGS));
  const [justSaved, setJustSaved] = React.useState(false);

  const dirty = !settingsEqual(saved, draft);

  // Clear the "Saved" confirmation as soon as the user edits again.
  React.useEffect(() => {
    if (dirty) setJustSaved(false);
  }, [dirty]);

  const setChannelMaster = (id: ChannelId, value: boolean) =>
    setDraft((d) => ({
      ...d,
      channels: { ...d.channels, [id]: { ...d.channels[id], master: value } },
    }));

  const setChannelType = (id: ChannelId, type: NotificationTypeId, value: boolean) =>
    setDraft((d) => ({
      ...d,
      channels: {
        ...d.channels,
        [id]: { ...d.channels[id], types: { ...d.channels[id].types, [type]: value } },
      },
    }));

  const handleSave = () => {
    setSaved(clone(draft));
    setJustSaved(true);
  };

  const handleDiscard = () => {
    setDraft(clone(saved));
    setJustSaved(false);
  };

  return (
    <main className="flex-1 bg-background py-8 sm:py-12">
      <Container size="md" className="flex flex-col gap-6">
        <header className="flex flex-col gap-1">
          <h1 className="text-2xl font-semibold tracking-tight text-foreground">
            通知設定
          </h1>
          <p className="text-sm text-muted-foreground">
            どの方法で、いつお知らせするかを選べます。変更は保存すると反映されます。
          </p>
        </header>

        {/* Delivery level + digest */}
        <Card>
          <CardHeader>
            <CardTitle>配信</CardTitle>
            <CardDescription>
              どれくらいのアクティビティを、どのくらいの頻度でまとめてお届けするか。
            </CardDescription>
          </CardHeader>
          <CardContent className="flex flex-col gap-6">
            <fieldset className="flex flex-col gap-3">
              <legend className="text-sm font-medium text-foreground">
                通知レベル
              </legend>
              <RadioGroup
                value={draft.level}
                onValueChange={(v) =>
                  setDraft((d) => ({ ...d, level: v as Settings["level"] }))
                }
                aria-label="通知レベル"
              >
                {[
                  { value: "all", label: "すべてのアクティビティ", hint: "起きたことすべて" },
                  { value: "mentions", label: "メンションのみ", hint: "自分が関わったときだけ" },
                  { value: "none", label: "なし", hint: "すべてミュート" },
                ].map((opt) => (
                  <div key={opt.value} className="flex items-start gap-3">
                    <RadioGroupItem value={opt.value} id={`level-${opt.value}`} className="mt-0.5" />
                    <div className="flex flex-col">
                      <Label htmlFor={`level-${opt.value}`} className="cursor-pointer">
                        {opt.label}
                      </Label>
                      <span className="text-xs text-muted-foreground">{opt.hint}</span>
                    </div>
                  </div>
                ))}
              </RadioGroup>
            </fieldset>

            <Separator />

            <div className="flex flex-col gap-2">
              <Label htmlFor="digest-frequency">ダイジェストの頻度</Label>
              <Select
                id="digest-frequency"
                value={draft.digest}
                onChange={(e) =>
                  setDraft((d) => ({
                    ...d,
                    digest: e.target.value as Settings["digest"],
                  }))
                }
                className="sm:max-w-xs"
              >
                <option value="instant">即時 — 発生したらすぐに</option>
                <option value="daily">毎日 — 1日1回</option>
                <option value="weekly">毎週 — 月曜にまとめて</option>
              </Select>
              <p className="text-xs text-muted-foreground">
                緊急でない通知は1つのダイジェストにまとめられます。
              </p>
            </div>

            <Separator />

            <div className="flex flex-col gap-3">
              <div className="flex items-center justify-between">
                <Label htmlFor="threshold">重要度のしきい値</Label>
                <Badge variant="secondary">{draft.threshold}</Badge>
              </div>
              <Slider
                id="threshold"
                min={0}
                max={100}
                step={5}
                value={draft.threshold}
                onValueChange={(n) => setDraft((d) => ({ ...d, threshold: n }))}
                aria-label="重要度のしきい値"
                className="w-full"
              />
              <p className="text-xs text-muted-foreground">
                この重要度以上の項目だけ通知します。
              </p>
            </div>
          </CardContent>
        </Card>

        {/* Channels */}
        <Card>
          <CardHeader>
            <CardTitle>チャネル</CardTitle>
            <CardDescription>
              チャネルをオフにすると完全に無音にできます。種類ごとに細かく調整することもできます。
            </CardDescription>
          </CardHeader>
          <CardContent className="p-0">
            <Accordion type="multiple" defaultValue={["email", "push"]} className="border-0">
              {CHANNELS.map((channel) => {
                const state = draft.channels[channel.id];
                return (
                  <AccordionItem key={channel.id} value={channel.id} className="last:border-b-0">
                    <div className="flex items-center justify-between gap-3 px-4">
                      <AccordionTrigger className="flex-1 hover:no-underline">
                        <div className="flex flex-col items-start text-left">
                          <span className="text-sm font-medium text-foreground">
                            {channel.label}
                          </span>
                          <span className="text-xs font-normal text-muted-foreground">
                            {channel.description}
                          </span>
                        </div>
                      </AccordionTrigger>
                      {/* Master switch lives outside the trigger so toggling it
                          does not expand/collapse the section. */}
                      <Switch
                        checked={state.master}
                        onCheckedChange={(v) => setChannelMaster(channel.id, v)}
                        aria-label={`${channel.label}の通知をすべて有効にする`}
                      />
                    </div>
                    <AccordionContent>
                      <div className="flex flex-col gap-4 pt-1">
                        {NOTIFICATION_TYPES.map((type) => {
                          const id = `${channel.id}-${type.id}`;
                          return (
                            <div key={type.id} className="flex items-center justify-between gap-4">
                              <div className="flex flex-col">
                                <Label
                                  htmlFor={id}
                                  className="cursor-pointer text-foreground"
                                >
                                  {type.label}
                                </Label>
                                <span className="text-xs text-muted-foreground">
                                  {type.description}
                                </span>
                              </div>
                              <Switch
                                id={id}
                                checked={state.master && state.types[type.id]}
                                disabled={!state.master}
                                onCheckedChange={(v) =>
                                  setChannelType(channel.id, type.id, v)
                                }
                                aria-label={`${channel.label}で${type.label}を受け取る`}
                              />
                            </div>
                          );
                        })}
                      </div>
                    </AccordionContent>
                  </AccordionItem>
                );
              })}
            </Accordion>
          </CardContent>
        </Card>

        {/* Quiet hours */}
        <Card>
          <CardHeader>
            <CardTitle>サイレント時間</CardTitle>
            <CardDescription>
              この時間帯は緊急でない通知を保留します。
            </CardDescription>
          </CardHeader>
          <CardContent className="flex flex-col gap-4">
            <div className="flex items-center justify-between gap-4">
              <Label htmlFor="quiet-toggle">サイレント時間を有効にする</Label>
              <Switch
                id="quiet-toggle"
                checked={draft.quietHoursEnabled}
                onCheckedChange={(v) =>
                  setDraft((d) => ({ ...d, quietHoursEnabled: v }))
                }
                aria-label="サイレント時間を有効にする"
              />
            </div>
            <div className="flex flex-col gap-4 sm:flex-row sm:items-end sm:gap-8">
              <div className="flex flex-col gap-2">
                <Label id="quiet-start-label">開始</Label>
                <TimePicker
                  value={draft.quietStart}
                  onValueChange={(v) =>
                    setDraft((d) => ({ ...d, quietStart: v }))
                  }
                  minuteStep={15}
                  disabled={!draft.quietHoursEnabled}
                  hourLabel="サイレント時間の開始 — 時"
                  minuteLabel="サイレント時間の開始 — 分"
                />
              </div>
              <div className="flex flex-col gap-2">
                <Label id="quiet-end-label">終了</Label>
                <TimePicker
                  value={draft.quietEnd}
                  onValueChange={(v) =>
                    setDraft((d) => ({ ...d, quietEnd: v }))
                  }
                  minuteStep={15}
                  disabled={!draft.quietHoursEnabled}
                  hourLabel="サイレント時間の終了 — 時"
                  minuteLabel="サイレント時間の終了 — 分"
                />
              </div>
            </div>
          </CardContent>
        </Card>

        {/* Save bar */}
        <div className="sticky bottom-0 z-10 -mx-4 border-t bg-background/95 px-4 py-3 backdrop-blur sm:mx-0 sm:rounded-lg sm:border">
          <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
            <p className="text-sm" aria-live="polite">
              {dirty ? (
                <span className="flex items-center gap-2 text-foreground">
                  <span
                    aria-hidden
                    className="inline-block h-2 w-2 rounded-full bg-warning-strong"
                  />
                  保存されていない変更があります
                </span>
              ) : justSaved ? (
                <span className="text-success-strong">すべての変更を保存しました</span>
              ) : (
                <span className="text-muted-foreground">変更はありません</span>
              )}
            </p>
            <div className="flex gap-2">
              <Button variant="outline" onClick={handleDiscard} disabled={!dirty}>
                破棄
              </Button>
              <Button variant="primary" onClick={handleSave} disabled={!dirty}>
                変更を保存
              </Button>
            </div>
          </div>
        </div>
      </Container>
    </main>
  );
}
